                // Find next hop
                for (const auto& link : links) {
                    if (link.to == currentNode) {
                        info.nextHop[msg.originator] = link.from;
                        break;
                    }
                }
            }

            // Rebroadcast
            for (const auto& link : links) {
                if (link.from == currentNode) {
                    OGM newMsg = msg;
                    newMsg.hopCount++;
                    newMsg.quality *= link.quality;

                    queue.push({link.to, newMsg});
